  1	import React, { FC, useMemo } from 'react';
  2	
  3	import FormPFSelect from '@kubevirt-utils/components/FormPFSelect/FormPFSelect';
  4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  5	import {
  6	  SetTopConsumerData,
  7	  TopConsumersData,
  8	} from '@kubevirt-utils/hooks/useKubevirtUserSettings/utils/types';
  9	import { Card, SelectOption } from '@patternfly/react-core';
 10	
 11	import { TopConsumerMetric } from './topConsumerMetric';
 12	import { TopConsumersChartList } from './TopConsumersChartList';
 13	import { TopConsumerScope } from './topConsumerScope';
 14	
 15	import './TopConsumerCard.scss';
 16	
 17	type TopConsumersMetricCard = {
 18	  cardID: string;
 19	  localStorageData: TopConsumersData;
 20	  setLocalStorageData: SetTopConsumerData;
 21	};
 22	
 23	const TopConsumerCard: FC<TopConsumersMetricCard> = ({
 24	  cardID,
 25	  localStorageData,
 26	  setLocalStorageData,
 27	}) => {
 28	  const { t } = useKubevirtTranslation();
 29	
 30	  const metricKey = useMemo(
 31	    () => localStorageData?.[cardID]?.metric?.value,
 32	    [cardID, localStorageData],
 33	  );
 34	
 35	  const scopeKey = useMemo(
 36	    () => localStorageData?.[cardID]?.scope?.value,
 37	    [cardID, localStorageData],
 38	  );
 39	
 40	  const onMetricSelect = (value) => {
 41	    setLocalStorageData(cardID, {
 42	      ...localStorageData?.[cardID],
 43	      metric: {
 44	        ...localStorageData?.[cardID]?.metric,
 45	        value: TopConsumerMetric.fromDropdownLabel(value).toString(),
 46	      },
 47	    });
 48	  };
 49	  const onScopeSelect = (value) => {
 50	    setLocalStorageData(cardID, {
 51	      ...localStorageData?.[cardID],
 52	      scope: {
 53	        ...localStorageData?.[cardID]?.scope,
 54	        value: TopConsumerScope.fromDropdownLabel(value).toString(),
 55	      },
 56	    });
 57	  };
 58	
 59	  return (
 60	    <Card className="co-overview-card--gradient kv-top-consumer-card__metric-card">
 61	      <div className="kv-top-consumer-card__header">
 62	        <div>
 63	          <FormPFSelect
 64	            onSelect={(e, value) => onMetricSelect(value)}
 65	            selected={t(TopConsumerMetric.fromString(metricKey)?.getDropdownLabel())}
 66	            toggleProps={{ id: 'kv-top-consumers-card-metric-select' }}
 67	          >
 68	            {TopConsumerMetric.getAll().map((metric) => (
 69	              <SelectOption key={metric?.getValue()} value={t(metric?.getDropdownLabel())}>
 70	                {t(metric?.getDropdownLabel())}
 71	              </SelectOption>
 72	            ))}
 73	          </FormPFSelect>
 74	        </div>
 75	        <div className="kv-top-consumer-card__scope-select">
 76	          <FormPFSelect
 77	            onSelect={(e, value) => onScopeSelect(value)}
 78	            selected={t(TopConsumerScope.fromString(scopeKey)?.getDropdownLabel())}
 79	            toggleProps={{ id: 'kv-top-consumers-card-scope-select' }}
 80	          >
 81	            {TopConsumerScope.getAll().map((scope) => (
 82	              <SelectOption key={scope?.getValue()} value={t(scope?.getDropdownLabel())}>
 83	                {t(scope?.getDropdownLabel())}
 84	              </SelectOption>
 85	            ))}
 86	          </FormPFSelect>
 87	        </div>
 88	      </div>
 89	      <div className="kv-top-consumer-card__chart-header">
 90	        <div>{t('Resource')}</div>
 91	        <div>{t('Usage')}</div>
 92	      </div>
 93	      <TopConsumersChartList
 94	        localStorageData={localStorageData}
 95	        metric={TopConsumerMetric.fromString(metricKey)}
 96	        scope={TopConsumerScope.fromString(scopeKey)}
 97	      />
 98	    </Card>
 99	  );
100	};
101	
102	export default TopConsumerCard;

